// Function to get migration directories using the 'find' command
async function getMigrationDirectories() {
  try {
    const command = `find "${migrationsBasePath}" -type d -name migrations`;
    const { stdout } = await util.promisify(exec)(command);
    return stdout.trim().split('\n');
  } catch (error) {
    console.error(`Error executing the command: ${error}`);
    return [];
  }
}

