const BASE = CHARSET.length;
const BASIC_KEY_LENGTH = 8;

const logger = require('./logger');

function makeBasicKey() {
  let maxNumber = Math.pow(BASE, BASIC_KEY_LENGTH);
  let id = Math.floor(Math.random() * maxNumber);
  let str = new Array(BASIC_KEY_LENGTH);
  let curDigit;
  for (let i = BASIC_KEY_LENGTH - 1; i > -1; i--) {
    maxNumber = Math.pow(BASE, i);
    curDigit = id > maxNumber ? Math.floor(id / maxNumber) : 0;
    str[BASIC_KEY_LENGTH - i - 1] = CHARSET.charAt(curDigit);
    id = id - curDigit * maxNumber;
  }
  str = str.join('');
  return str;
}

