function _replaceWithVariableValue(replacableText, variableObject){
  const variableSymbol = '$_';
  if (!replacableText)
    return null;
  const wordsList = replacableText.split(/[,.;`'"<> ]+/);
  const stringReplaceMapping = {};
  wordsList.forEach(word => {
    if(word.includes(variableSymbol)){
      const wordVariable = word.split(variableSymbol)[1];
      stringReplaceMapping[wordVariable] = variableObject[wordVariable];
    }
  });
  for(const key of Object.keys(stringReplaceMapping)){
    replacableText = replacableText.replace(RegExp(`\\$\\_${key}\\$\\_`, 'g'), stringReplaceMapping[key]);
  }
  return replacableText;
}

