function _areObjectsEqual(a, b) {
  if ((a && !b) || (!a && b)) {
    return false;
  }
  if (!a && !b) {
    return true;
  }
  // Create arrays of property names
  const aKeys = Object.getOwnPropertyNames(a);
  const bKeys = Object.getOwnPropertyNames(b);

  // check number of properties
  if (aKeys.length !== bKeys.length) {
    return false;
  }

  // check if values of A exist in B
  for (key in a) {
    if (typeof a[key] === 'object') { // object OR array
      if (!_areObjectsEqual(a[key], b[key])) {
        return false;
      }
    } else if (a[key] !== b[key]) {
      return false;
    }
  }

  return true;
}

