function getUniquePropertyValuesFromJSONObject(obj, parameterObj){

  let responseSet = {};
  let keys = Object.keys(parameterObj);
  for(let i = 0;i<keys.length;i++){
    let result = obj.map(elem => elem[parameterObj[keys[i]]]);
    let resultSet = new Set();
    result.forEach(res => {
      if(!res || !res.length)
        return;
      res.forEach(item => resultSet.add(item))
    })
    responseSet[keys[i]] = [...resultSet];
  }
  return responseSet;
}

