async function axiosRetry(options, retryCount, statusCodes=[]){
  const logger = require('./logger');
  let retries = 0;
  let error = null;

  while (retries < retryCount) {
    try {
      const response = await axios(options);
      return response;
    } catch (err) {
      let status = 500;
      if(err && err.response && err.response.status){
        status = err.response.status
      }
      if(!statusCodes.includes(status)){
        throw new Error(err)
      }
      error = err;
      logger.error(`Axios call Error Status: ${status}`);
    }
    retries++
  }
  logger.error(`Axios call - Too many request reqtries.`);
  throw new Error(error)
};

