function getUniquePropertyValuesFromObject(obj) {
  let keys = Object.keys(obj[0]);
  let resultSet = {};
  for (let i = 0; i < keys.length; i++) {
    let result = obj.map(elem => elem[keys[i]]);
    resultSet[keys[i]] = [...new Set(result)];
  }
  return resultSet;
}

