  logger.info(`applyCurrencyConversion: Applying conversion rate for finances`);
  for (const finance of finances) {
    if (finance.requested_currency !== baseCurrency) {
      let rate = rateMap[finance.requested_currency] || 1;
      if (finance.conversion_rate) rate = finance.conversion_rate;
      finance.requested_amount = parseFloat(convertAmount(finance.requested_amount, rate).toFixed(2));
      if(finance.receivable_amount) {
        finance.receivable_amount = parseFloat(convertAmount(finance.receivable_amount, rate).toFixed(2));
      }
      if (finance.outstanding_amount) {
        finance.outstanding_amount = convertAmount(finance.outstanding_amount, rate);
      }
    }
  }
  return finances;
};

