const headers = function (userId = null, orgHId=null, tenantFuntionName=null, userToken = null) {
  let tenantCode = tenantEntity.DTF;
  try{
    tenantCode = getTenantCode(tenantFuntionName);
  }
  catch(err) {
    logger.warn(`headers: Tenant Code is not present so defaulting it to ${tenantCode}`);
  }
  tenantCode = tenantCode;
  const h = {};
  if (userId) {
    h['X-Org-Id'] = orgHId;
    h['X-User-Id'] = userId;
    h['X-Tenant-Code'] = tenantCode;
    h['X-DPW-User-Token'] = userToken ? userToken : getUserToken(`lendingAPI Header`) ;
  }
  return h;
};

