async function sendEmailForFailedSyncReq(syncReq, errorMessage){

  let recipientList = syncFailAlertEmailId.map(emailId => {
    return new UserOrgEmailObject(emailId);
  });

  let message = `Sync request from arranging to lending - 

  ${JSON.stringify(syncReq)}

  Error - ${errorMessage}`;

  await sendEmailNotification(
    db,
    recipientList,
    null,
    null,
    emailTypes.SYNC_REQ_FAILURE,
    message,
    `Failed Sync request - Arranging to Lending`
  );
}

